import{_ as o,c as t,o as a,ag as c}from"./chunks/framework.Bw-5EFTY.js";const g=JSON.parse('{"title":"Playground Specification","description":"","frontmatter":{},"headers":[],"relativePath":"packages/agent-playground/SPEC.md","filePath":"packages/agent-playground/SPEC.md"}'),d={name:"packages/agent-playground/SPEC.md"};function r(n,e,i,s,l,u){return a(),t("div",null,e[0]||(e[0]=[c('<h1 id="playground-specification" tabindex="-1">Playground Specification <a class="header-anchor" href="#playground-specification" aria-label="Permalink to &quot;Playground Specification&quot;">​</a></h1><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p>Owns the Robota Playground UI package: React components, hooks, executor logic, plugins, and tool catalog for interactive agent experimentation in the browser. Provides <code>PlaygroundApp</code> and <code>PlaygroundDemo</code> components, <code>PlaygroundExecutor</code> for managing Robota agents via <code>RemoteExecutor</code>, and statistics/history plugins for real-time visualization.</p><h2 id="boundaries" tabindex="-1">Boundaries <a class="header-anchor" href="#boundaries" aria-label="Permalink to &quot;Boundaries&quot;">​</a></h2><ul><li>Does not own core agent contracts (<code>IExecutor</code>, <code>IAIProvider</code>, <code>TUniversalMessage</code>); imports from <code>@robota-sdk/agent-core</code>.</li><li>Does not own remote transport contracts; imports <code>RemoteExecutor</code> from <code>@robota-sdk/agent-remote</code>.</li><li>Does not own WebSocket message types; imports <code>IPlaygroundWebSocketMessage</code> from <code>@robota-sdk/agent-remote</code>.</li><li>Does not define deployment or hosting behavior; that belongs to <code>apps/web</code>.</li></ul><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><p>Facade-pattern executor (<code>PlaygroundExecutor</code>) wraps Robota agent instances for browser-based execution. AI providers are constructed with a <code>RemoteExecutor</code> so API keys stay server-side. Two plugins (<code>PlaygroundHistoryPlugin</code>, <code>PlaygroundStatisticsPlugin</code>) are standalone classes that collect conversation events and UX metrics. React hooks (<code>usePlaygroundBoot</code>, <code>usePlaygroundData</code>, <code>useRobotaExecution</code>, etc.) provide state management; these hooks are used internally by the React components and are not part of the public package API. A <code>PlaygroundWebSocketClient</code> enables real-time communication with the API server. Block-tracking layer (<code>PlaygroundBlockCollector</code>, <code>LLMTracker</code>, <code>PlaygroundBlockVisualizationSubscriber</code>) handles execution block collection and real-time visualization data. Tool catalog (<code>ToolRegistry</code>) provides built-in playground tools created via factory functions; it is used internally and is not exported from the public entry point.</p><h2 id="type-ownership" tabindex="-1">Type Ownership <a class="header-anchor" href="#type-ownership" aria-label="Permalink to &quot;Type Ownership&quot;">​</a></h2><p>This package is SSOT for:</p><ul><li><code>IPlaygroundAgentConfig</code> -- playground-specific agent configuration.</li><li><code>IPlaygroundExecutorResult</code> -- execution result with visualization data and UI error.</li><li><code>IPlaygroundTool</code> / <code>IPlaygroundPlugin</code> -- playground tool and plugin contracts.</li><li><code>TPlaygroundMode</code> -- execution mode (<code>&#39;agent&#39;</code>).</li><li><code>IPlaygroundUiError</code> / <code>TPlaygroundUiErrorKind</code> -- UI-facing error classification.</li><li><code>IPlaygroundMetrics</code> / <code>IPlaygroundStatisticsOptions</code> / <code>IPlaygroundStatisticsStats</code> -- statistics types.</li><li><code>IPlaygroundAction</code> -- UI interaction action type.</li><li><code>IPlaygroundExecutionResult</code> -- statistics execution result.</li><li><code>IPlaygroundBootState</code> -- boot hook state.</li><li><code>PLAYGROUND_STATISTICS_EVENTS</code> -- statistics event constants.</li></ul><h2 id="public-api-surface" tabindex="-1">Public API Surface <a class="header-anchor" href="#public-api-surface" aria-label="Permalink to &quot;Public API Surface&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Export</th><th>Kind</th><th>Description</th></tr></thead><tbody><tr><td><code>PlaygroundApp</code></td><td>React component</td><td>Full playground application shell</td></tr><tr><td><code>PlaygroundDemo</code></td><td>React component</td><td>Demo-mode playground</td></tr><tr><td><code>PlaygroundExecutor</code></td><td>class</td><td>Agent lifecycle and execution facade (re-exported from services)</td></tr><tr><td><s><code>usePlaygroundBoot</code></s></td><td>hook (internal)</td><td>Boot state management — not exported from package entry</td></tr></tbody></table><p>Note: <code>usePlaygroundData</code>, <code>useRobotaExecution</code>, <code>useChatInput</code>, and <code>ToolRegistry</code> are used internally by the package&#39;s own components and are not exported from the public entry point (<code>src/index.ts → src/playground/index.ts</code>).</p><h2 id="extension-points" tabindex="-1">Extension Points <a class="header-anchor" href="#extension-points" aria-label="Permalink to &quot;Extension Points&quot;">​</a></h2><ul><li><code>IPlaygroundTool</code> -- consumers can implement custom tools with <code>name</code>, <code>description</code>, <code>schema</code>, and <code>execute</code>.</li><li><code>IPlaygroundPlugin</code> -- consumers can implement custom plugins with <code>initialize</code> and <code>dispose</code> lifecycle.</li><li><code>ToolRegistry</code> -- tool factory functions that accept <code>IEventService</code> and return <code>FunctionTool</code>.</li></ul><h2 id="error-taxonomy" tabindex="-1">Error Taxonomy <a class="header-anchor" href="#error-taxonomy" aria-label="Permalink to &quot;Error Taxonomy&quot;">​</a></h2><p>Errors are returned in <code>IPlaygroundExecutorResult</code> using the <code>IPlaygroundUiError</code> classification:</p><table tabindex="0"><thead><tr><th>Kind</th><th>Condition</th></tr></thead><tbody><tr><td><code>user_message</code></td><td>Validation errors, invalid input, unknown tool</td></tr><tr><td><code>fatal</code></td><td>Strict-policy violations, path-only failures, no-fallback violations</td></tr><tr><td><code>recoverable</code></td><td>Transient/system errors (default classification)</td></tr></tbody></table><p>Runtime errors: <code>&#39;No active agent to execute prompt&#39;</code>, <code>&#39;Server URL and auth token required&#39;</code>, <code>&#39;Unknown tool id&#39;</code>, agent/tool registry lookup failures.</p><h2 id="class-contract-registry" tabindex="-1">Class Contract Registry <a class="header-anchor" href="#class-contract-registry" aria-label="Permalink to &quot;Class Contract Registry&quot;">​</a></h2><h3 id="interface-implementations" tabindex="-1">Interface Implementations <a class="header-anchor" href="#interface-implementations" aria-label="Permalink to &quot;Interface Implementations&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Interface</th><th>Implementor</th><th>Kind</th><th>Location</th></tr></thead><tbody><tr><td><code>IPlaygroundBlockCollector</code></td><td><code>PlaygroundBlockCollector</code></td><td>production</td><td><code>src/lib/playground/block-tracking/block-collector.ts</code></td></tr></tbody></table><h3 id="inheritance-chains" tabindex="-1">Inheritance Chains <a class="header-anchor" href="#inheritance-chains" aria-label="Permalink to &quot;Inheritance Chains&quot;">​</a></h3><p>None. <code>PlaygroundStatisticsPlugin</code> and <code>PlaygroundHistoryPlugin</code> are standalone classes that do not extend any base class.</p><h3 id="cross-package-port-consumers" tabindex="-1">Cross-Package Port Consumers <a class="header-anchor" href="#cross-package-port-consumers" aria-label="Permalink to &quot;Cross-Package Port Consumers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Port (Owner)</th><th>Consumer</th><th>Location</th></tr></thead><tbody><tr><td><code>Robota</code> (agent-core)</td><td><code>PlaygroundExecutor</code></td><td><code>src/lib/playground/robota-executor.ts</code></td></tr><tr><td><code>FunctionTool</code> (agent-tools)</td><td>Tool factory functions</td><td><code>src/tools/</code></td></tr><tr><td><code>RemoteExecutor</code> (remote)</td><td><code>PlaygroundExecutor</code></td><td><code>src/lib/playground/robota-executor.ts</code></td></tr><tr><td><code>IPlaygroundWebSocketMessage</code> (remote)</td><td><code>PlaygroundWebSocketClient</code></td><td><code>src/lib/playground/websocket-client.ts</code></td></tr></tbody></table><h2 id="test-strategy" tabindex="-1">Test Strategy <a class="header-anchor" href="#test-strategy" aria-label="Permalink to &quot;Test Strategy&quot;">​</a></h2><ul><li><strong>No test files found</strong> in this package currently.</li><li>Statistics types and plugin logic have no unit test coverage.</li><li>React components and hooks have no test coverage.</li><li>Recommended: unit tests for <code>PlaygroundExecutor</code> methods, <code>toPlaygroundUiError</code> classification, and statistics plugin recording.</li></ul>',28)]))}const p=o(d,[["render",r]]);export{g as __pageData,p as default};
